sql:
SELECT user_name
FROM users
WHERE user_id IN (SELECT DISTINCT user_id FROM feedback);

external_knowledge:
; A machine learning model is a mathematical model that is trained on data to make predictions or decisions; 
; User feedback is typically collected in the form of ratings on a scale of 1 to 5, where 1 is the lowest and 5 is the highest;
; The evaluation metrics refer to the number of times each model has been evaluated, which can be a measure of its usage or adoption;
; The latest performance metrics are determined by the most recent timestamp in the model_performance_history table.

sql:
SELECT DISTINCT model_id
FROM evaluations
WHERE accuracy = (SELECT MAX(accuracy) FROM evaluations);
